SELECT s.*
FROM ts_chat_session s
WHERE s.user_id = #{query.userId}

    AND s.session_type = #{query.sessionType}


    AND s.target_role_id = #{query.targetRoleId}


    AND s.story_id = #{query.storyId}


    AND s.session_title LIKE CONCAT('%', #{query.keyword}, '%')


    AND s.last_message_at >= #{query.lastMessageAtStart}


    AND s.last_message_at <= #{query.lastMessageAtEnd}



        AND s.session_status = #{query.sessionStatus}


        AND s.session_status != 0


ORDER BY COALESCE(s.last_message_at, s.updated_at) DESC, s.id DESC

SELECT s.*
FROM ts_chat_session s
WHERE s.id = #{id}
  AND s.user_id = #{userId}
  AND s.session_status != 0
LIMIT 1
